[{"type":"tool_result","tool_use_id":"toolu_01KnDoxRYazFMpGh8qy2dWKq","content":[{"type":"text","text":"import { useEffect, useMemo, useState } from 'react';
import { CandleChart } from './components/CandleChart';
import { Watchlist } from './components/Watchlist';
import { IndicatorPanel } from './components/IndicatorPanel';
import { DataLoader } from './components/DataLoader';
import { BacktestPanel } from './components/BacktestPanel';
import { Panel, Button } from './components/ui';
import { useStore, useActiveCandles } from './store/useStore';
import { preloadEngine } from './engine';
import { cn } from './lib/utils';
import type { Candle } from './types';

const TIMEFRAMES = [
  { id: '1D', days: 1 },
  { id: '1W', days: 7 },
  { id: '1M', days: 30 },
  { id: '3M', days: 90 },
  { id: '1Y', days: 365 },
  { id: 'ALL', days: Infinity },
] as const;

type TimeframeId = (typeof TIMEFRAMES)[number]['id'];

/** Filters candles to the trailing window for the selected timeframe. */
function filterTimeframe(candles: Candle[], days: number): Candle[] {
  if (!Number.isFinite(days) || candles.length === 0) return candles;
  const last = candles[candles.length - 1].time;
  const cutoff = last - days * 86_400;
  return candles.filter((c) => c.time >= cutoff);
}

export default function App() {
  const init = useStore((s) => s.init);
  const activeSymbol = useStore((s) => s.activeSymbol);
  const allCandles = useActiveCandles();
  const indicators = useStore((s) => s.indicators);
  const loading = useStore((s) => s.loading);
  const error = useStore((s) => s.error);
  const clearError = useStore((s) => s.clearError);
  const storageReady = useStore((s) => s.storageReady);
  const [timeframe, setTimeframe] = useState<TimeframeId>('1Y');

  useEffect(() => {
    preloadEngine();
    void init();
  }, [init]);

  const days = TIMEFRAMES.find((t) => t.id === timeframe)?.days ?? Infinity;
  const candles = useMemo(
    () => filterTimeframe(allCandles, days),
    [allCandles, days],
  );

  const last = candles[candles.length - 1];

  return (
    <div className="flex h-screen flex-col bg-base-900 text-slate-200">
      {/* Top bar */}
      <header className="flex shrink-0 items-center justify-between border-b border-base-700 px-4 py-2.5">
        <div className="flex items-center gap-3">
          <div className="flex items-center gap-2">
            <Logo />
            <span className="text-lg font-bold tracking-tight text-slate-100">
              Axiomic
            </span>
          </div>
          <span className="hidden text-xs text-slate-500 sm:inline">
            Browser-first stock analysis · Rust + WASM
          </span>
        </div>
        <div className="flex items-center gap-2">
          <span
            className={cn(
              'rounded-full px-2 py-0.5 text-[11px]',
              storageReady
                ? 'bg-accent-up/15 text-accent-up'
                : 'bg-base-700 text-slate-400',
            )}
          >
            {storageReady ? 'DuckDB ready' : 'In-memory'}
          </span>
        </div>
      </header>

      {error && (
        <div className="flex items-center justify-between border-b border-accent-down/40 bg-accent-down/10 px-4 py-2 text-sm text-accent-down">
          <span>{error}</span>
          <button onClick={clearError} aria-label="Dismiss error">
            ×
          </button>
        </div>
      )}

      {/* Body */}
      <div className="grid min-h-0 flex-1 grid-cols-[220px_1fr_300px] gap-2 p-2">
        {/* Left: watchlist + data */}
        <div className="flex min-h-0 flex-col gap-2">
          <Panel title="Watchlist" className="min-h-0 flex-1">
            <Watchlist />
          </Panel>
          <Panel title="Data" className="shrink-0">
            <DataLoader />
          </Panel>
        </div>

        {/* Center: chart */}
        <Panel
          title={`${activeSymbol}${last ? ` · ${last.close.toFixed(2)}` : ''}`}
          className="min-h-0"
          action={
            <div className="flex items-center gap-1">
              {TIMEFRAMES.map((tf) => (
                <Button
                  key={tf.id}
                  variant={tf.id === timeframe ? 'accent' : 'ghost'}
                  onClick={() => setTimeframe(tf.id)}
                  className="px-2 py-1 text-xs"
                >
                  {tf.id}
                </Button>"}],"cache_control":{"type":"ephemeral"}}]

