        textColor: '#94a3b8',
        fontFamily: 'ui-sans-serif, system-ui, sans-serif',
      },
      grid: { vertLines: { color: GRID }, horzLines: { color: GRID } },
      crosshair: { mode: CrosshairMode.Normal },
