function resampleCandles(candles: Candle[], id: TimeframeId): Candle[] {
  if (id === '1D' || id === 'ALL' || candles.length === 0) return candles;
  const out: Candle[] = [];
  let cur: Candle | null = null;
  let curKey: number | null = null;
